const body = $input.first().json.body ?? $input.first().json;

const event = body.event ?? '';
const data  = body.data  ?? {};
const key   = data.key   ?? {};

const remoteJid   = key.remoteJid  ?? '';
const fromMe      = key.fromMe     ?? false;
const pushName    = data.pushName  ?? 'Cliente';
const instance    = body.instance  ?? '';
const messageType = data.messageType ?? '';

const msg = data.message ?? {};

// Extrai texto
const texto =
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.imageMessage?.caption ||
  '';

// Dados do áudio (se houver)
const isAudio = ['audioMessage', 'pttMessage'].includes(messageType);
const audioData = isAudio ? (msg.audioMessage ?? msg.pttMessage ?? null) : null;

const numero  = remoteJid.replace(/@.+/, '');
const isGroup = remoteJid.includes('@g.us');

// Passa a mensagem original completa para download de mídia
return [{
  json: {
    event, fromMe, isGroup, pushName,
    numero, remoteJid, instance,
    messageType, isAudio, audioData,
    texto: texto.trim(),
    // Para download via Evolution API
    rawMessage: data.message,
    rawKey: key,
  }
}];

// Converte base64 retornado pela Evolution API para arquivo binário
const item = $input.first();
const base64 = item.json.base64 ?? item.json.data ?? '';
const mimeType = item.json.mimetype ?? 'audio/ogg';

if (!base64) throw new Error('Evolution API não retornou base64 do áudio');

const buffer = Buffer.from(base64, 'base64');

return [{
  json: { ...item.json },
  binary: {
    audio: {
      data: base64,
      mimeType,
      fileName: 'audio.ogg',
      fileExtension: 'ogg',
    }
  }
}];

// Merge: pega o texto transcrito e injeta no item original da sessão
const transcription = $input.first().json.text ?? '';

// Recupera dados da sessão do nó anterior
const sessao = $('Dados da sessão').first().json;

return [{
  json: {
    ...sessao,
    texto: transcription,
    isAudioTranscribed: true,
  }
}];

